#include <iostream>
#include <cassert>
#include <vector>
#include <sstream>

using namespace std;

class SearchSpace {
    vector<string> space;
    public:
    SearchSpace(const vector<string> &s) : space(s) {}

    bool remove(size_t x, size_t y) {
        if (space[x][y] != '@') return false;
        int count = 0;
        for (int dx = -1; dx <= 1; ++dx) {
            for (int dy = -1; dy <= 1; ++dy) {
                if (dx == 0 && dy == 0) continue;
                int nx = x + dx;
                int ny = y + dy;
                if (nx < space.size() && nx >= 0 && ny < space[nx].size() && ny >= 0 && space[nx][ny] == '@') {
                    count++;
                }
            }
        }
        if (count < 4)
        {
            space[x][y] = '.';
            return true;
        }

        return false;
    }
};

