int main () {

    SearchSpace ss(space_string);
    unsigned int count = 0;
    unsigned int temp_count = 1;
    while (temp_count != 0) {
        temp_count = 0;
        for (size_t i = 0; i < space_string.size(); ++i) {
            for (size_t j = 0; j < space_string[i].size(); ++j) {
                if (ss.remove(i, j))
                    temp_count++;
            }
        }
        count += temp_count;
    }
    cout << "Count: " << count << endl;

    return 0;
}
